def cubic(Tf, t):
    a = t/Tf
    return 3*a**2 - 2*a**3

def cubic_dot(Tf, t):
    a = t/Tf
    return (6/Tf)*a*(1-a)

def quintic(Tf, t):
    a = t/Tf
    return 10*a**3 - 15*a**4 + 6*a**5

ch10.solution:
def grid_neighbors(r, c, rows, cols):
    out=[]
    for dr,dc in ((-1,0),(1,0),(0,-1),(0,1)):
        nr,nc=r+dr,c+dc
        if 0<=nr<rows and 0<=nc<cols: out.append([nr,nc])
    return sorted(out)

